exercises.solutionCode:
import pandas as pd

df = pd.DataFrame({
    'name': ['Charlie', 'Bob', 'Alice', 'Ed'],
    'age': [35, 30, 25, 28]
})

print(df.sort_values('name', key=lambda x: x.str.len()))

